import{_ as e,o as i,c as l,ak as r}from"./chunks/framework.Chu_0La1.js";const b=JSON.parse('{"title":"指令帮助","description":"","frontmatter":{},"headers":[],"relativePath":"help/index.md","filePath":"doc/help/index.md"}'),t={name:"help/index.md"};function s(o,a,n,c,h,d){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="指令帮助" tabindex="-1">指令帮助 <a class="header-anchor" href="#指令帮助" aria-label="Permalink to “指令帮助”">​</a></h1><p>欢迎使用 mzkbot！以下是详细的功能指令指南。</p><h2 id="功能分类" tabindex="-1">功能分类 <a class="header-anchor" href="#功能分类" aria-label="Permalink to “功能分类”">​</a></h2><h3 id="基础功能" tabindex="-1">基础功能 <a class="header-anchor" href="#基础功能" aria-label="Permalink to “基础功能”">​</a></h3><ul><li><a href="./basic/chat">基础对话</a> - AI 智能对话功能</li><li><a href="./basic/signin">每日签到</a> - 每日签到获取奖励</li></ul><h3 id="娱乐互动" tabindex="-1">娱乐互动 <a class="header-anchor" href="#娱乐互动" aria-label="Permalink to “娱乐互动”">​</a></h3><ul><li><a href="./entertainment/guess-song">PJSK猜歌</a> - 根据音频猜歌曲</li><li><a href="./entertainment/guess-card">PJSK猜卡面</a> - 根据卡面局部猜角色</li><li><a href="./entertainment/guess-jacket">PJSK猜曲绘</a> - 根据曲绘局部猜歌曲</li><li><a href="./entertainment/guess-lyrics">PJSK歌词猜曲</a> - 根据歌词猜歌曲</li><li><a href="./entertainment/music">网易云点歌</a> - 智能点歌系统</li></ul><div class="warning custom-block github-alert"><p class="custom-block-title">娱乐功能限制</p><p>由于部分群聊使用频率过大导致 bot 经常被风控，现已限制其他群聊的娱乐功能使用，请移步至 mzkbot 的娱乐功能专群 <strong>1098198311</strong> 游玩。</p></div><h3 id="其他功能" tabindex="-1">其他功能 <a class="header-anchor" href="#其他功能" aria-label="Permalink to “其他功能”">​</a></h3><ul><li><a href="./other/video">流媒体解析</a> - 支持 B站、抖音、小红书等平台</li><li><a href="./other/group">入群/退群提示</a> - 自动欢迎和送别</li><li><a href="./other/status">服务器状态监控</a> - 系统运行状态</li></ul><h3 id="sakurabot-专项功能" tabindex="-1">SakuraBOT 专项功能 <a class="header-anchor" href="#sakurabot-专项功能" aria-label="Permalink to “SakuraBOT 专项功能”">​</a></h3><div class="important custom-block github-alert"><p class="custom-block-title">使用须知</p><p></p><ul><li>运行以下 SakuraBOT 指令时，<strong>不需要</strong>添加 <code>@mzkbot</code> 前缀，直接发送指令即可</li><li><strong>多服支持</strong>：涉及用户数据的指令，可添加 <code>tw</code> 或 <code>cn</code> 前缀来触发台服/国服专属功能（默认为日服）</li></ul></div><ul><li><a href="./sakura/user-data">用户数据管理</a> - 绑定账号、设置权限</li><li><a href="./sakura/advanced">高阶数据分析</a> - 需要上传数据的分析功能</li><li><a href="./sakura/deck">智能卡组推荐</a> - 基于卡牌数据的卡组推荐</li><li><a href="./sakura/tools">查询与工具箱</a> - 活动查询、歌曲查询、卡牌查询等</li></ul><hr><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h2><ol><li><strong>新手入门</strong> - 了解 <a href="./basic/chat">基础对话</a> 和 <a href="./basic/signin">每日签到</a></li><li><strong>娱乐功能</strong> - 体验 <a href="./entertainment/guess-song">PJSK猜歌</a> 等小游戏</li><li><strong>游戏助手</strong> - 使用 SakuraBOT 专项功能查询游戏数据</li></ol><hr><div class="tip custom-block github-alert"><p class="custom-block-title">使用提示</p><p></p><ul><li>大部分指令需要在群聊中 <code>@mzkbot</code> 后输入</li><li>SakuraBOT 专项功能 <strong>不需要</strong> <code>@mzkbot</code> 前缀</li><li>高峰期可能出现延迟，请耐心等待</li></ul></div>',18)])])}const m=e(t,[["render",s]]);export{b as __pageData,m as default};
